# FFN variants compared
class ReLUFFN(nn.Module):
    def __init__(self, d_model, d_ff):
        super().__init__()
        self.w1 = nn.Linear(d_model, d_ff, bias=False)
        self.w2 = nn.Linear(d_ff, d_model, bias=False)
    def forward(self, x):
        return self.w2(F.relu(self.w1(x)))

class SwiGLUFFN(nn.Module):
    def __init__(self, d_model, d_ff):
        super().__init__()
        # SwiGLU uses 3 projections (gate, up, down)
        # d_ff for SwiGLU is typically 8/3 * d_model
        self.gate = nn.Linear(d_model, d_ff, bias=False)
        self.up   = nn.Linear(d_model, d_ff, bias=False)
        self.down = nn.Linear(d_ff, d_model, bias=False)
    def forward(self, x):
        return self.down(F.silu(self.gate(x)) * self.up(x))

# Quality equivalence: SwiGLU d_ff = ReLU d_ff * 2/3
# Llama 2 7B (ReLU): d_ff=11008 → Llama 3 8B (SwiGLU): d_ff=14336
# 14336 ≈ 11008 / (2/3) = 16512 (close enough)
